# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import json
import requests

# Define your RabbitMQ management endpoint URL
mgmt_url = "http://localhost:15672/api/"

# Credentials to access RabbitMQ Management API
username = "guest"
password = "guest"

def authenticate_api():
    auth_headers = {
        "Content-Type": "application/json",
        "Accept": "*/*"
    }
    data = {"username": username, "password": password}
    response = requests.post(mgmt_url + 'vhosts', headers=auth_headers, data=json.dumps(data))
    return json.loads(response.text)

def create_vhost(vhost_name):
    auth_token = authenticate_api()["token"]
    headers = {
        "Authorization": f"Bearer {auth_token}",
        "Content-Type": "application/json",
        "Accept": "*/*"
    }
    response = requests.post(mgmt_url + 'vhosts', headers=headers, data=json.dumps({"name": vhost_name}))
    return json.loads(response.text)

def create_user(vhost_name, user_name):
    auth_token = authenticate_api()["token"]
    headers = {
        "Authorization": f"Bearer {auth_token}",
        "Content-Type": "application/json",
        "Accept": "*/*"
    }
    response = requests.post(mgmt_url + 'users', headers=headers, data=json.dumps({"username": user_name, "password": "password", "vhost": vhost_name}))
    return json.loads(response.text)

def grant_permissions(vhost_name, user_name):
    auth_token = authenticate_api()["token"]
    headers = {
        "Authorization": f"Bearer {auth_token}",
        "Content-Type": "application/json",
        "Accept": "*/*"
    }
    response = requests.post(mgmt_url + 'permissions', headers=headers, data=json.dumps({
            "vhost": vhost_name,
            "user": user_name,
            "resources": [
                {
                    "privileges": ["write", "read"],
                    "resource": "queue.*"
                },
                {
                    "privileges": ["write", "read"],
                    "resource": "exchange.*"
                }
            ]
        }))
    return json.loads(response.text)

# Example usage:
vhost_name = "app1"
user_name = "app1_user"

create_vhost(vhost_name)
create_user(vhost_name, user_name)
grant_permissions(vhost_name, user_name)